// ── Lexical node helpers ─────────────────────────────────────────────────────

type TextNode = { type: 'text'; text: string; format?: number; version: 1 }
type ParagraphNode = { type: 'paragraph'; children: TextNode[]; version: 1 }
type HeadingNode = { type: 'heading'; tag: 'h1' | 'h2' | 'h3'; children: TextNode[]; version: 1 }
type ListItemNode = { type: 'listitem'; children: TextNode[]; value: number; version: 1 }
type ListNode = { type: 'list'; listType: 'bullet' | 'number'; children: ListItemNode[]; start: 1; tag: 'ul' | 'ol'; version: 1 }
type LexicalRoot = { root: { type: 'root'; children: (ParagraphNode | HeadingNode | ListNode)[]; direction: 'ltr'; format: ''; indent: 0; version: 1 } }

function t(text: string, format = 0): TextNode { return { type: 'text', text, format, version: 1 } }
function p(...texts: TextNode[]): ParagraphNode { return { type: 'paragraph', children: texts, version: 1 } }
function h3(text: string): HeadingNode { return { type: 'heading', tag: 'h3', children: [t(text)], version: 1 } }
function ul(...items: string[]): ListNode {
  return { type: 'list', listType: 'bullet', tag: 'ul', start: 1,
    children: items.map((item, i): ListItemNode => ({ type: 'listitem', value: i + 1, children: [t(item)], version: 1 })),
    version: 1 }
}
function lex(...nodes: (ParagraphNode | HeadingNode | ListNode)[]): LexicalRoot {
  return { root: { type: 'root', children: nodes, direction: 'ltr', format: '', indent: 0, version: 1 } }
}

